import { MagneticText } from "@/components/ui/magnetic-text";

export default function PullQuote() {
  return (
    <blockquote className="mx-auto max-w-2xl border-l-2 border-purple-500 px-8 py-16">
      <MagneticText
        text="The best UI is the one users never have to think about."
        radius={220}
        strength={18}
        className="text-2xl italic text-neutral-200"
      />
    </blockquote>
  );
}

